package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStreamReader;
import java.io.Reader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private URL mockUrl;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        mockUrl = mock(URL.class);
        charset = Charset.forName("UTF-8");
        format = CSVFormat.DEFAULT;
    }

    @Test
    void parse_validUrl_returnsCSVParser() throws Exception {
        InputStreamReader mockReader = mock(InputStreamReader.class);
        InputStreamReader realReader = new InputStreamReader(mockUrl.openStream(), charset);

        // Mock url.openStream() to return a dummy InputStream
        var mockInputStream = mock(java.io.InputStream.class);
        when(mockUrl.openStream()).thenReturn(mockInputStream);

        // Mock constructor of InputStreamReader to return mockReader when called with mockInputStream and charset
        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // Mock Assertions.notNull to do nothing
            assertionsMockedStatic.when(() -> Assertions.notNull(any(), any())).then(invocation -> null);

            // Spy CSVParser constructor call via partial mocking using spy on constructor is not possible,
            // so just call real method and verify not null
            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            assertEquals(format, parser.format);
        }
    }

    @Test
    void parse_nullUrl_throwsException() {
        assertThrows(NullPointerException.class, () -> CSVParser.parse(null, charset, format));
    }

    @Test
    void parse_nullCharset_throwsException() {
        assertThrows(NullPointerException.class, () -> CSVParser.parse(mockUrl, null, format));
    }

    @Test
    void parse_nullFormat_throwsException() {
        assertThrows(NullPointerException.class, () -> CSVParser.parse(mockUrl, charset, null));
    }
}
